const today = new Date().toISOString().split('T')[0];
const all = items[0].json.allData || [];
const results = [];
var appMap = {'web':'Online Store','pos':'Point of Sale','mobile':'Shop','shopify_draft_order':'Draft Orders','iphone':'Shop','android':'Shop'};
var locationMap = {
  '61845110897': '2061 West 4th Ave',
  '34791915633': '418 Davie Street, Vancouver',
  '70972768369': '486 Front St W - The Well, Toronto',
  '69315657841': '510 8 Ave SW - Holt Renfrew, Calgary',
  '61826072689': '79 Yorkville, Toronto',
  '42702532': '1025 Howe Street, Vancouver',
  '61808017521': 'Consignment - Real Real',
  '61822697585': "Courtney's Closet",
  '191632': 'Storage Locker',
  '61841834097': 'West 4th - Back of House (Archived)'
};
function getApp(s){ return appMap[s] || s || 'Unknown'; }
function getLocationName(id){ return id ? (locationMap[id.toString()] || 'Unknown Location') : null; }
function getWeek(ds){
  var d=new Date(ds); d.setHours(0,0,0,0);
  d.setDate(d.getDate()+3-(d.getDay()+6)%7);
  var w=new Date(d.getFullYear(),0,4);
  return 1+Math.round(((d-w)/86400000-3+(w.getDay()+6)%7)/7);
}
for (var i = 0; i < all.length; i++) {
  var o = all[i];
  var cat = o.created_at || '';
  var od = cat.split('T')[0] || today;
  var dobj = new Date(cat);
  var yr = dobj.getFullYear().toString();
  var mo = ('0'+(dobj.getMonth()+1)).slice(-2);
  var wk = getWeek(cat).toString();
  var ym = yr+'|'+(dobj.getMonth()+1);
  var lis = o.line_items || [];
  var tqty = lis.reduce(function(s,l){return s+(l.quantity||0);},0);
  var sa = o.shipping_address || {};
  var sl = o.shipping_lines || [];
  var sp = sl.length > 0 ? parseFloat(sl[0].price)||0 : 0;
  var locId = o.location_id ? o.location_id.toString() : null;
  var custId = o.customer ? o.customer.id.toString() : null;
  var base = {
    account_name:'mine-yours-co.myshopify.com', date:od, month:mo,
    order_app_name:getApp(o.source_name), order_created_at:cat, order_currency:o.currency||'',
    order_customer_last_visit_utm_campaign:null, order_customer_last_visit_utm_medium:null,
    order_customer_last_visit_utm_source:null,
    order_financial_status:(o.financial_status||'').toUpperCase(),
    order_id:(o.id||'').toString(), order_name:o.name||'',
    order_net_sales:parseFloat(o.subtotal_price)||0, order_processed_at:o.processed_at||null,
    order_quantity:tqty, order_shipping_address_country:sa.country||null,
    order_shipping_address_province:sa.province||null, order_shipping_price:sp,
    order_subtotal_price:parseFloat(o.subtotal_price)||0,
    order_test:o.test?'True':'False',
    order_total_discounts:parseFloat(o.total_discounts)||0,
    order_total_price:parseFloat(o.total_price)||0,
    source:'shopify', week:wk, year:yr, year_month:ym,
    order_total_tax_amount:parseFloat(o.total_tax)||0,
    order_location_id:locId,
    order_location_name:getLocationName(locId),
    order_customer_id:custId
  };
  if (lis.length === 0) {
    results.push({json: Object.assign({}, base, {line_item__id:null,line_item__price:null,line_item__product_id:null,line_item__quantity:null,line_item__sku:null,line_item__title:null,line_item__total_discount:null,line_item__variant_unit_cost:null,line_item__vendor:null})});
  } else {
    for (var j=0;j<lis.length;j++){
      var li=lis[j];
      results.push({json: Object.assign({}, base, {
        line_item__id:(li.id||'').toString(), line_item__price:parseFloat(li.price)||0,
        line_item__product_id:(li.product_id||'').toString(), line_item__quantity:li.quantity||0,
        line_item__sku:li.sku||'', line_item__title:li.title||'',
        line_item__total_discount:parseFloat(li.total_discount)||0,
        line_item__variant_unit_cost:null, line_item__vendor:li.vendor||''
      })});
    }
  }
}
if (results.length === 0) return [{json:{message:'No orders updated in last 2 days'}}];
return results;

